def _splice(extra):
    for bab in BAB:
        no = bab["no"]; isi = bab["isi"]
        if no in extra:
            idx = next((i for i, blk in enumerate(isi) if blk[0] == "h2" and "Ringkasan" in blk[1]), len(isi))
            bab["isi"] = isi[:idx] + extra[no] + isi[idx:]
    _renumber()

